// 手机兼容设计的商品块
// 商品详情块，商品显示主样式
<template>
<div class="phone-block" ondragstart="return false;">
  <!-- 预留图，淡出离开 -->
  <transition name="into">
    <div class="ready" v-if="!isShow">
    <!-- <div class="ready" v-if="true"> -->
      <div class="ready_pic">
        <img :src="ready.pic" />
      </div>
      <div class="ready_text">
        <img :src="ready.text" />
        <img :src="ready.text" />
      </div>
      <!-- 虽然是价格预留图，但是实际使用的是文字预留图，设定百分比宽 -->
      <div class="ready_price">
        <img :src="ready.text" />
      </div>
    </div>
  </transition>

  <!-- 真正商品信息，淡入进入 -->
  <transition name="into">
    <div class="details" v-if="isShow">
    <!-- <div class="details" v-if="false"> -->
      <!-- 图片 -->
      <img class="pic" :class="{mouse: isEnter}" :src="message.pic" />
      <!-- 文字 -->
      <p class="text" v-text="message.text" :title="message.text" />
      <!-- 价格 -->
      <div class="price">
        <!-- 单位 -->
        <span class="company" v-html="'&yen;'" />
        <!-- 数字 -->
        <span class="num_int" v-text="num_int" />
        <span class="num_float" v-text="'.'" v-if="num_float" />
        <span class="num_float" v-text="num_float" v-if="num_float" />
      </div>
    </div>
  </transition>

  <!-- 占位层，样式继承预留图，透明度 0 -->
  <div class="seat ready">
    <div class="ready_pic">
      <img :src="ready.pic" />
    </div>
    <div class="ready_text">
      <img :src="ready.text" />
      <img :src="ready.text" />
    </div>
    <div class="ready_price">
      <img :src="ready.text" />
    </div>
  </div>
</div>
</template>

<script>
import imgReady from 'ts/shopping/imgReady'

export default {
  name: 'tributary',
  props: {
    message: Object,
    ready: Object
  },
  data() {
    return {
      isShow: false,
      isEnter: false,
      num_int: String,
      num_float: String
    }
  },
  mounted() {
    // 获取的数字，转字符串，小数点、整数分离显示
    let num = this.message.price.toString().split(".")
    this.num_int = num[0]
    this.num_float = num[1]

    // 确认加载好了图片以后
    new imgReady([this.message.pic])
    .load().then((src) => {
      //！！！故意停留 3 秒刷新
      setTimeout(() => {
        this.isShow = true;
      }, 3000)
    })
  },
  methods: {
    enter() {
      this.isEnter = true;
    },
    leave() {
      this.isEnter = false;
    }
  }
}
</script>

