// 判断 观察对象 是否 从下方 进入可视区
// 参数：滚动条对象、观察对象、额外视距(额外像素距离) + 滚动条对象的 观察对象的 下方其他盒子总高度
class seeing {
  scroll: any // 滚动条 DOM对象
  aim: any // 观察 DOM对象
  additional: number// 额外视距
  shows?: boolean // 显示状态

  constructor(scroll: object, aim: object, additional?: number) {
    this.scroll = scroll
    this.aim = aim

    if(additional != undefined) {
      this.additional = additional
    } else {
      this.additional = 0
    }
  }

  // 是否进入范围
  isIn() {
    // 如果可视距离到了提示盒子的顶部
    // 滚动条到底部的距离 <= 提示盒子高度 + 图标盒子高度 + 其他
    // if(this.scroll_bottom <= this.scroll.offsetHeight + 50) {
    if(this.inspect() <= this.scroll.offsetHeight + this.additional) {
      this.shows = true
    } else {
      this.shows = false
    }

    return this.shows
  }

  // 检查
  inspect() {
    // 获取滚动条的总高度
    let scroll_height = this.scroll.scrollHeight
    // 获取可视区的高度
    let window_height = this.scroll.clientHeight
    // 获取滚动条距离顶部的高度
    let scroll_top = this.scroll.scrollTop
    // 滚动条到底部的距离 = 滚动条的总高度 - 可视区的高度 - 滚动条距离顶部的高度
    return scroll_height - window_height - scroll_top
  }
}

export default seeing