// 小屏状态下的提示盒子
<template>
<!-- 小于524像素 && 触顶，过渡显示提示盒子 -->
<transition name="tips" ref="tips" class="tips-box">
  <tributary
  :message="tips"
  :ready="ready"
  v-if="isShow"
  />
</transition>
</template>

<script>
import tributary from './tributary'
import seeing from 'ts/seeing'

export default {
  name: "tips-box",
  data() {
    return {
      cont: {},
      width: Boolean, // 宽度满足条件
      height: Boolean, // 高度满足条件
      isOver: false, // 是否加载完成
      see: Object // 判断可视区对象
    }
  },
  components: {
    tributary
  },
  props: {
    ready: Object, // 广告预留图
    tips: Object // 提示、广告数据
  },
  mounted() {
    // 单独运行一次
    this.docWidth()

    window.addEventListener('resize', () => this.docWidth(), false)

    // ！！！指向滚动条容器
    this.cont = this.$refs.tips.parentNode.parentNode.parentNode.parentNode

    this.see = new seeing(this.cont, this.$refs.tips, 50)

    // 绑定滚动条滚动，触发 ifTop 事件
    this.cont.addEventListener('scroll', this.ifTop, true)
  },
  computed: {
    isShow() {
      return (this.width && this.height) || (this.width && this.isOver)
    }
  },
  methods: {
    over() {
      this.isOver = true
    },
    // 每当页面宽度改变时运行
    docWidth() {
      // 获取页面宽度
      let doc_width = window.innerWidth

      // 页面宽度小于 524 像素
      if(doc_width < 524) {
        this.width = true
      } else {
        this.width = false
      }
    },
    // 是否接近可视区
    ifTop() { 
      if(this.see.isIn()) {
        this.height = true
      } else {
        this.height = false
      }
      
    }
  }
}
</script>

<style lang="less" scoped>
.tips-box {
  transform: translateZ(0);
}

.tips-enter-active {
  animation: tips-in 2s;
}

@keyframes tips-in {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}

// 宽度大于490
@media screen and (min-width: 490px) {
  .tips-box {
    display: none;
  }
}
</style>