<template>
  <span class="rotate-icon ico icon-spinner11" :style="rotateStyle" />
</template>

<script>
export default {
  name: 'rotate-icon',
  data() {
    return {
      // 是否进行选转
      ifRotate: true,
      // 旋转圈数
      frequency: 0,
      // 无限循环选转的事件
      RotateEvent: 0,
      // 旋转的 css
      rotateStyle: {},
      // 首次动画快速启动
      once: true
    }
  },
  methods: {
    // 开始旋转
    rotate() {
      // 是否允许旋转
      if(this.ifRotate) {
        // 防抖
        this.ifRotate = false

        // 直接运行一遍旋转动画
        this.circle()
        // 关闭首次动画快速启动
        this.once = false

        // 无限循环旋转
        this.RotateEvent = setInterval(() => {
          this.circle()
        }, 800)
      }
    },
    // 转圈动画
    circle() {
      // 圈数加一
      this.frequency++;

      this.rotateStyle = {
        transition: 'transform .8s',
        transform: 'rotate(' + this.frequency * 360 + 'deg)',
      }
    },
    // 停止旋转
    stop() {
      // 打开首次动画快速启动
      this.once = true
      // 停止无限旋转
      clearTimeout(this.RotateEvent);
      // 等待最后一圈动画完成以后
      setTimeout(() => {
        // 可以再次开始旋转
        this.ifRotate = true
      }, 800)
    }
  }
}
</script>

<style lang="less" scoped>
.ico {
  position: absolute;
  left: calc(50% - (@rotate_icon / 2));
  width: @rotate_icon;
  height: @rotate_icon;
  text-align: center;
  line-height: @rotate_icon;
  color: @qing;
  user-select: none;
  font-size: 1.2rem;
}
</style>