// 支流
// 商品详情块包装，主要控制动画与flex样式，确认图片加载
<template>
<div class="tributary" @mouseover="mouseEnter()" @mouseleave="mouseLeave()">
  <!-- 商品详情块正式内容 -->
  <phone-block ref="phone_block" :message="message" :ready="ready" />
</div>
</template>

<script>
import phoneBlock from 'shopping/shopping-block/phone-block.vue'

export default {
  name: 'tributary',
  props: {
    message: Object,
    ready: Object
  },
  components: {
    phoneBlock
  },
  methods: {
    mouseEnter() {
      this.$refs.phone_block.enter()
    },
    mouseLeave() {
      this.$refs.phone_block.leave()
    }
  }
}
</script>

